1	import { useState, useEffect } from "react";
2	
3	import { Toaster } from "@/components/ui/toaster";
4	import { Toaster as Sonner } from "@/components/ui/sonner";
5	import { TooltipProvider } from "@/components/ui/tooltip";
6	import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
7	import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
8	import { ThemeProvider } from "@/components/ThemeProvider";
9	import { LanguageProvider } from "@/i18n/LanguageContext";
10	import { supabase } from "@/integrations/supabase/client";
11	import { useInitializeE2EE } from "@/hooks/use-initialize-e2ee";
12	import { RecoveryPasswordModal } from "@/components/auth/RecoveryPasswordModal";
13	import { SetRecoveryPasswordDialog } from "@/components/auth/SetRecoveryPasswordDialog";
14	import ScrollToTop from "./components/ScrollToTop";
15	
16	import Home from "./pages/Home";
17	import Auth from "./pages/Auth";
18	import ResetPassword from "./pages/ResetPassword";
19	import CreatorSignup from "./pages/CreatorSignup";
20	import BrandSignup from "./pages/BrandSignup";
21	import Kira from "./pages/Kira";
22	import CreviaLink from "./pages/CreviaLink";
23	import CreviaStudio from "./pages/CreviaStudio";
24	import WorkspacesList from "./pages/WorkspacesList";
25	import MFAVerify from "./components/auth/MFAVerify";
26	import WorkspacePage from "./pages/WorkspacePage";
27	import PublicProfile from "./pages/PublicProfile";
28	import NotFound from "./pages/NotFound";
29	import PaymentsBilling from "./pages/profile/PaymentsBilling";
30	import Notifications from "./pages/profile/Notifications";
31	import Verification from "./pages/profile/Verification";
32	import Settings from "./pages/profile/Settings";
33	import Help from "./pages/profile/Help";
34	import Feedback from "./pages/profile/Feedback";
35	import Pricing from "./pages/Pricing";
36	import About from "./pages/About";
37	import PrivacyPolicy from "./pages/PrivacyPolicy";
38	import TermsOfService from "./pages/TermsOfService";
39	import AppLayout from "./components/navigation/AppLayout";
40	import PublicPageWrapper from "./components/PublicPageWrapper";
41	import ProtectedRoute from "./components/auth/ProtectedRoute";
42	
43	const queryClient = new QueryClient();
44	
45	// AppContent lives inside BrowserRouter so routing hooks are available.
46	// useInitializeE2EE is called HERE — at the very top of this component,
47	// before any conditional returns — so React's rules of hooks are never violated.
48	function AppContent() {
49	  const [userId, setUserId] = useState("");
50	
51	  // MUST be called before any early returns.
52	  // Receives "" until the auth state resolves, then fires the full init flow.
53	  const {
54	    error: e2eeError,
55	    needsRecoveryPassword,
56	    needsMigration,
57	    provideRecoveryPassword,
58	    clearMigrationFlag,
59	  } = useInitializeE2EE(userId);
60	
61	  const [migrationDialogOpen, setMigrationDialogOpen] = useState(false);
62	
63	  // Open the migration dialog as soon as the flag is raised, but only once per session.
64	  useEffect(() => {
65	    if (needsMigration) setMigrationDialogOpen(true);
66	  }, [needsMigration]);
67	
68	  useEffect(() => {
69	    // onAuthStateChange fires immediately with the current session
70	    // (INITIAL_SESSION event) AND fires again on every sign-in / sign-out.
71	    // This is more reliable than getSession() which can return null on the
72	    // first tick in OAuth / server-redirect flows.
73	    const {
74	      data: { subscription },
75	    } = supabase.auth.onAuthStateChange((_event, session) => {
76	      setUserId(session?.user?.id ?? "");
77	    });
78	
79	    return () => subscription.unsubscribe();
80	  }, []);
81	
82	  return (
83	    <>
84	      <ScrollToTop />
85	
86	      {/* Non-dismissible: shown on a new device when a v2 backup exists */}
87	      <RecoveryPasswordModal
88	        open={needsRecoveryPassword}
89	        error={e2eeError}
90	        onSubmit={provideRecoveryPassword}
91	      />
92	
93	      {/* Dismissible: nudges v1 users and new users to set a recovery password */}
94	      <SetRecoveryPasswordDialog
95	        open={migrationDialogOpen}
96	        userId={userId}
97	        onOpenChange={setMigrationDialogOpen}
98	        onComplete={clearMigrationFlag}
99	      />
100	
101	      <Routes>
102	        {/* Public routes */}
103	        <Route path="/" element={<PublicPageWrapper><Home /></PublicPageWrapper>} />
104	        <Route path="/auth" element={<PublicPageWrapper><Auth /></PublicPageWrapper>} />
105	        <Route path="/reset-password" element={<PublicPageWrapper><ResetPassword /></PublicPageWrapper>} />
106	        <Route path="/pricing" element={<PublicPageWrapper><Pricing /></PublicPageWrapper>} />
107	        <Route path="/about" element={<PublicPageWrapper><About /></PublicPageWrapper>} />
108	        <Route path="/app/about" element={<AppLayout><About /></AppLayout>} />
109	        <Route path="/privacy-policy" element={<AppLayout><PrivacyPolicy /></AppLayout>} />
110	        <Route path="/terms-of-service" element={<AppLayout><TermsOfService /></AppLayout>} />
111	        <Route path="/user-type-selection" element={<Navigate to="/auth" replace />} />
112	        <Route path="/signup/creator" element={<PublicPageWrapper><CreatorSignup /></PublicPageWrapper>} />
113	        <Route path="/signup/brand" element={<PublicPageWrapper><BrandSignup /></PublicPageWrapper>} />
114	        <Route path="/:username" element={<PublicPageWrapper><PublicProfile /></PublicPageWrapper>} />
115	
116	        {/* Protected routes */}
117	        <Route path="/dashboard" element={<Navigate to="/kira" replace />} />
118	        <Route path="/kira" element={<ProtectedRoute><AppLayout><Kira /></AppLayout></ProtectedRoute>} />
119	        <Route path="/crevia-link" element={<ProtectedRoute><AppLayout><CreviaLink /></AppLayout></ProtectedRoute>} />
120	        <Route path="/crevia-studio" element={<ProtectedRoute><AppLayout><CreviaStudio /></AppLayout></ProtectedRoute>} />
121	        <Route path="/mfa-verify" element={<MFAVerify />} />
122	        <Route path="/crevia-workspace" element={<ProtectedRoute><AppLayout><WorkspacesList /></AppLayout></ProtectedRoute>} />
123	        <Route path="/crevia-workspace/:id" element={<ProtectedRoute><AppLayout><WorkspacePage /></AppLayout></ProtectedRoute>} />
124	        <Route path="/profile/payments-billing" element={<ProtectedRoute><AppLayout><PaymentsBilling /></AppLayout></ProtectedRoute>} />
125	        <Route path="/profile/notifications" element={<ProtectedRoute><AppLayout><Notifications /></AppLayout></ProtectedRoute>} />
126	        <Route path="/profile/verification" element={<ProtectedRoute><AppLayout><Verification /></AppLayout></ProtectedRoute>} />
127	        <Route path="/profile/settings" element={<ProtectedRoute><AppLayout><Settings /></AppLayout></ProtectedRoute>} />
128	        <Route path="/profile/help" element={<ProtectedRoute><AppLayout><Help /></AppLayout></ProtectedRoute>} />
129	        <Route path="/profile/feedback" element={<ProtectedRoute><AppLayout><Feedback /></AppLayout></ProtectedRoute>} />
130	
131	        <Route path="*" element={<NotFound />} />
132	      </Routes>
133	    </>
134	  );
135	}
136	
137	const App = () => (
138	  <QueryClientProvider client={queryClient}>
139	    <ThemeProvider attribute="class" defaultTheme="light" enableSystem={false} storageKey="theme">
140	      <LanguageProvider>
141	        <TooltipProvider>
142	          <Toaster />
143	          <Sonner />
144	          <BrowserRouter>
145	            <AppContent />
146	          </BrowserRouter>
147	        </TooltipProvider>
148	      </LanguageProvider>
149	    </ThemeProvider>
150	  </QueryClientProvider>
151	);
152	
153	export default App;
154	

