5	import { Input } from "@/components/ui/input";
6	import { Label } from "@/components/ui/label";
7	import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
8	import { supabase } from "@/integrations/supabase/client";
9	import { useToast } from "@/hooks/use-toast";
