14	const hasOAuthCallback = () => {
15	  const params = new URLSearchParams(window.location.search);
16	  return params.has("code") || params.has("token_hash") || window.location.hash.includes("access_token");
17	};
18	
19	const Auth = () => {
20	  const navigate = useNavigate();
21	  const [searchParams] = useSearchParams();
22	  const { toast } = useToast();
23	  const [isSignup, setIsSignup] = useState(searchParams.get("mode") === "signup");
24	  const [email, setEmail] = useState("");
25	  const [password, setPassword] = useState("");
26	  const [showPassword, setShowPassword] = useState(false);
27	  const [showForgotPassword, setShowForgotPassword] = useState(false);
28	  const [resetEmail, setResetEmail] = useState("");
29	  const [isResetting, setIsResetting] = useState(false);
30	  const [isGoogleLoading, setIsGoogleLoading] = useState(false);
31	  // const [isAppleLoading, setIsAppleLoading] = useState(false);
32	  const [isLoading, setIsLoading] = useState(false);
33	  const [userType, setUserType] = useState<"creator" | "brand">("creator");
34	  const [termsAccepted, setTermsAccepted] = useState(false);
35	  const [passwordErrors, setPasswordErrors] = useState<string[]>([]);
36	  const [emailConfirmPending, setEmailConfirmPending] = useState(false);
37	  const [pendingEmail, setPendingEmail] = useState("");
38	  // True when we landed here from a Google OAuth redirect — hide the form while Supabase exchanges the code.
39	  const [isProcessingOAuth, setIsProcessingOAuth] = useState(hasOAuthCallback);
40	
41	  const validatePassword = (pwd: string): string[] => {
42	    const errors: string[] = [];
43	    if (pwd.length < 8) errors.push("At least 8 characters");
44	    if (!/[A-Z]/.test(pwd)) errors.push("One uppercase letter");
45	    if (!/[a-z]/.test(pwd)) errors.push("One lowercase letter");
46	    if (!/[0-9]/.test(pwd)) errors.push("One number");
47	    if (!/[^A-Za-z0-9]/.test(pwd)) errors.push("One special character");
48	    return errors;
49	  };
50	
51	  const handlePasswordChange = (value: string) => {
52	    setPassword(value);
53	    if (isSignup) setPasswordErrors(validatePassword(value));
54	  };
55	
56	  useEffect(() => {
57	    // Check if user is already logged in
58	    supabase.auth.getSession().then(async ({ data: { session } }) => {
59	      if (session) {
60	        const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
61	        if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
62	          navigate("/mfa-verify", { replace: true });
63	        } else {
64	          navigate("/kira", { replace: true });
65	        }
66	      }
67	    });
68	
69	    // Listen for auth state changes (for OAuth redirects)
70	    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
71	      if (event === 'SIGNED_IN' && session) {
72	        const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
73	        if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
74	          navigate("/mfa-verify", { replace: true });
75	        } else {
76	          navigate("/kira", { replace: true });
77	        }
78	      } else if (isProcessingOAuth) {
79	        // Exchange failed or no session — fall back to showing the login form.
80	        setIsProcessingOAuth(false);
81	      }
82	    });
83	
84	    return () => subscription.unsubscribe();
85	  }, [navigate]);
86	
87	  const handleGoogleSignIn = async () => {
88	    if (isSignup && !termsAccepted) {
89	      toast({
90	        title: "Please agree first",
91	        description: "Tick the Terms of Use and Privacy Policy checkbox before continuing.",
92	        variant: "destructive",
93	      });
94	      return;
95	    }
96	
97	    setIsGoogleLoading(true);
98	    try {
99	      const { error } = await supabase.auth.signInWithOAuth({
100	        provider: 'google',
101	        options: {
102	          redirectTo: `${window.location.origin}/auth`,
103	          queryParams: {
104	            access_type: 'offline',
105	            prompt: 'select_account',
106	          },
107	        },
108	      });
109	
110	      if (error) {
111	        toast({
112	          title: "Google sign-in failed",
113	          description: error.message,
114	          variant: "destructive"
115	        });
116	        setIsGoogleLoading(false);
117	      }
118	    } catch (err) {
119	      console.error("Google auth error:", err);
120	      toast({
121	        title: "Connection error",
122	        description: "Unable to connect to Google. Please check your internet and try again.",
123	        variant: "destructive"
124	      });
125	      setIsGoogleLoading(false);
126	    }
127	  };
128	
129	  // const handleAppleSignIn = async () => {
130	  //   setIsAppleLoading(true);
131	  //   try {
132	  //     const { error } = await supabase.auth.signInWithOAuth({
133	  //       provider: 'apple',
134	  //       options: {
135	  //         redirectTo: `${window.location.origin}/auth`,
136	  //         queryParams: {
137	  //           prompt: 'login',
138	  //         },
139	  //       },
140	  //     });
141	
142	  //     if (error) {
143	  //       toast({ 
144	  //         title: "Apple sign-in failed 😅", 
145	  //         description: error.message, 
146	  //         variant: "destructive" 
147	  //       });
148	  //       setIsAppleLoading(false);
149	  //     }
150	  //   } catch (err) {
151	  //     console.error("Apple auth error:", err);
152	  //     toast({ 
153	  //       title: "Connection hiccup! 📡", 
154	  //       description: "Unable to connect to Apple. Please try again.", 
155	  //       variant: "destructive" 
156	  //     });
157	  //     setIsAppleLoading(false);
158	  //   }
159	  // };
160	
161	  const handleAuth = async (e: React.FormEvent) => {
162	    e.preventDefault();
163	    setIsLoading(true);
164	
165	    try {
166	      if (isSignup) {
167	        const errors = validatePassword(password);
168	        if (errors.length > 0) {
169	          setPasswordErrors(errors);
170	          setIsLoading(false);
171	          return;
172	        }
173	        const { data: signUpData, error } = await supabase.auth.signUp({
174	          email,
175	          password,
176	          options: {
177	            emailRedirectTo: `${window.location.origin}/auth`,
178	            data: {
179	              user_type: userType,
180	            },
181	          },
182	        });
183	
184	        if (error) {
185	          const msg = error.message.toLowerCase();
186	          if (msg.includes("already registered") || msg.includes("already exists")) {
187	            toast({
188	              title: "Account already exists",
189	              description: "An account with this email already exists. Try logging in instead.",
190	              variant: "destructive",
191	            });
192	            setIsSignup(false);
193	          } else if (msg.includes("rate limit") || msg.includes("email rate")) {
194	            toast({
195	              title: "Too many attempts",
196	              description: "Please wait a few minutes before trying again.",
197	              variant: "destructive",
198	            });
199	          } else {
200	            toast({
201	              title: "Sign up failed",
202	              description: "Something went wrong on our end. Please try again in a moment.",
203	              variant: "destructive",
204	            });
205	            console.error("Signup error:", error.message);
206	          }
207	        } else if (signUpData.session) {
208	          // User is immediately signed in (email confirmation disabled)
209	          const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
210	          if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
211	            navigate("/mfa-verify", { replace: true });
212	          } else {
213	            navigate("/kira", { replace: true });
214	          }
215	        } else {
216	          // Email confirmation required — show dedicated screen
217	          setPendingEmail(email);
218	          setEmailConfirmPending(true);
219	        }
220	      } else {
221	        const { data, error } = await supabase.auth.signInWithPassword({
222	          email,
223	          password,
224	        });
225	
226	        if (error) {
227	          const msg = error.message.toLowerCase();
228	          if (msg.includes("invalid login") || msg.includes("invalid credentials") || msg.includes("wrong password")) {
229	            toast({ title: "Incorrect email or password", description: "Please check your details and try again.", variant: "destructive" });
230	          } else if (msg.includes("email not confirmed")) {
231	            toast({ title: "Email not confirmed", description: "Please check your inbox and click the confirmation link we sent you.", variant: "destructive" });
232	          } else {
233	            toast({ title: "Sign in failed", description: error.message, variant: "destructive" });
234	          }
235	        } else if (data.user) {
236	          toast({ title: "Welcome back!", description: "Good to see you." });
237	          // navigation is handled by the onAuthStateChange SIGNED_IN listener above
238	        }
239	      }
240	    } catch (err) {
241	      console.error("Auth error:", err);
242	      toast({ 
243	        title: "Connection hiccup! 📡", 
244	        description: "Unable to connect to the server. Please check your internet and try again.", 
245	        variant: "destructive" 
246	      });
247	    } finally {
248	      setIsLoading(false);
249	    }
250	  };
251	
252	  const handleForgotPassword = async (e: React.FormEvent) => {
253	    e.preventDefault();
254	    setIsResetting(true);
255	
256	    const { error } = await supabase.auth.resetPasswordForEmail(resetEmail, {
257	      redirectTo: `${window.location.origin}/reset-password`,
258	    });
259	
260	    setIsResetting(false);
261	
262	    if (error) {
263	      toast({
264	        title: "Oops! 😅",
265	        description: error.message,
266	        variant: "destructive",
267	      });
268	    } else {
269	      toast({
270	        title: "Check your inbox! 📧",
271	        description: "We sent you a link to reset your password.",
272	      });
273	      setShowForgotPassword(false);
274	      setResetEmail("");
275	    }
276	  };
277	
278	  if (isProcessingOAuth) {
279	    return (
280	      <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4">
281	        <div className="flex flex-col items-center gap-4 text-center">
282	          <Loader2 className="w-10 h-10 animate-spin text-bronze" />
283	          <p className="font-poppins text-muted-foreground">Signing you in…</p>
284	        </div>
285	      </div>
286	    );
287	  }
288	
289	  if (emailConfirmPending) {
290	    return (
291	      <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4 md:p-6">
292	        <Card className="w-full max-w-md p-6 md:p-8 mx-4 animate-fade-in text-center">
293	          <div className="mb-6">
294	            <img src="/crevia-logo.png" alt="Crevia Logo" className="w-10 h-10 mx-auto mb-4" />
295	            <h1 className="font-vollkorn text-2xl font-bold mb-2">Check your inbox</h1>
296	            <p className="text-muted-foreground text-sm leading-relaxed">
297	              We sent a confirmation link to<br />
298	              <span className="font-semibold text-foreground">{pendingEmail}</span>
299	            </p>
300	          </div>
301	          <p className="text-sm text-muted-foreground mb-6">
302	            Click the link in your email to activate your account and access Kira. Check your spam folder if you don't see it.
303	          </p>
304	          <Button
305	            variant="outline"
306	            className="w-full h-12"
307	            onClick={() => { setEmailConfirmPending(false); setIsSignup(false); }}
308	          >
309	            Back to sign in
310	          </Button>
311	        </Card>
312	      </div>
313	    );
314	  }
315	
316	  return (
317	    <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4 md:p-6">
318	      <Card className="w-full max-w-md p-6 md:p-8 mx-4 animate-fade-in">
319	        <div className="text-center mb-6 md:mb-8">
320	          <Link to="/" className="inline-flex items-center gap-2 mb-4 md:mb-6 transition-all duration-[400ms] ease-[cubic-bezier(0.32,0.72,0,1)] hover:opacity-80">
321	            <img 
322	              src="/crevia-logo.png" 
323	              alt="Crevia Logo" 
324	              className="w-8 h-8 md:w-10 md:h-10 transition-transform duration-[400ms] ease-[cubic-bezier(0.32,0.72,0,1)] hover:scale-105" 
325	            />
326	            <span className="font-vollkorn text-2xl md:text-3xl font-bold">Crevia</span>
327	          </Link>
328	          <h1 className="font-vollkorn text-2xl md:text-3xl font-bold mb-2 animate-fade-in stagger-1 animate-stagger">
329	            {isSignup ? "Create your account" : "Welcome back"}
330	          </h1>
331	          <p className="text-sm md:text-base text-muted-foreground animate-fade-in stagger-2 animate-stagger">
332	            {isSignup ? "Sign up to get started" : "Log in to continue"}
333	          </p>
334	        </div>
335	
336	        {/* User Type Toggle - Only show for signup */}
337	        {isSignup && (
338	          <div className="mb-6">
339	            <Label className="text-sm font-medium text-muted-foreground mb-3 block text-center">
340	              I am a...
341	            </Label>
342	            <div className="grid grid-cols-2 gap-3">
343	              <button
344	                type="button"
345	                onClick={() => setUserType("creator")}
346	                className={cn(
347	                  "flex flex-col items-center gap-2 p-4 rounded-xl border-2 transition-all duration-300",
348	                  userType === "creator"
349	                    ? "border-bronze bg-bronze/10 text-bronze"
350	                    : "border-border hover:border-bronze/50 text-muted-foreground hover:text-foreground"
351	                )}
352	              >
353	                <User className="h-6 w-6" />
354	                <span className="font-poppins text-sm font-semibold">Creative</span>
355	              </button>
356	              <button
357	                type="button"
358	                onClick={() => setUserType("brand")}
359	                className={cn(
360	                  "flex flex-col items-center gap-2 p-4 rounded-xl border-2 transition-all duration-300",
361	                  userType === "brand"
362	                    ? "border-bronze bg-bronze/10 text-bronze"
363	                    : "border-border hover:border-bronze/50 text-muted-foreground hover:text-foreground"
364	                )}
365	              >
366	                <Building2 className="h-6 w-6" />
367	                <span className="font-poppins text-sm font-semibold">Brand</span>
368	              </button>
369	            </div>
370	          </div>
371	        )}
372	
373	        <div className="justify-center">
374	          <Button 
375	            variant="outline" 
376	            className="w-full h-12"
377	            onClick={handleGoogleSignIn}
378	            disabled={isGoogleLoading}
379	          >
380	            {isGoogleLoading ? (
381	              <Loader2 className="w-5 h-5 mr-2 animate-spin" />
382	            ) : (
