14	const AppLayout = ({ children }: AppLayoutProps) => {
15	  const location = useLocation();
16	  const { setTheme } = useTheme();
17	  const [userType, setUserType] = useState<"creator" | "brand" | null>(null);
18	  const [profile, setProfile] = useState<any>(null);
19	  const [loading, setLoading] = useState(true);
20	  const [profileDrawerOpen, setProfileDrawerOpen] = useState(false);
21	
22	  useEffect(() => {
23	    const appTheme = localStorage.getItem("app-theme");
24	    if (appTheme) {
25	      setTheme(appTheme);
26	    } else {
27	      setTheme("light");
28	      localStorage.setItem("app-theme", "light");
29	      localStorage.setItem("theme", "light");
30	    }
31	    loadProfile();
32	
33	    // Re-load profile when the session is established after a PKCE OAuth exchange
34	    // (getSession() above may return null if the code is still being exchanged).
35	    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
36	      if (event === "SIGNED_IN") {
37	        loadProfile();
38	      }
39	    });
40	
41	    return () => subscription.unsubscribe();
42	  }, []);
43	
44	  const loadProfile = async () => {
45	    const { data: { session } } = await supabase.auth.getSession();
46	
47	    if (session) {
48	      const { data: profileData } = await supabase
49	        .from("profiles")
50	        .select("*")
51	        .eq("id", session.user.id)
52	        .single();
53	
54	      setProfile(profileData);
55	      setUserType(profileData?.user_type || null);
56	    } else {
57	      setUserType("creator");
58	      setProfile({ display_name: "Guest", email: "" });
59	    }
60	    setLoading(false);
61	  };
62	
63	  if (loading) {
64	    return (
65	      <div className="min-h-screen bg-black flex items-center justify-center">
66	        <div className="text-white/60 font-poppins">Loading...</div>
67	      </div>
68	    );
69	  }
70	
71	  if (!userType || !profile) {
72	    return null;
73	  }
74	
75	  const isCrevidAI = location.pathname === "/crevia-ai";
76	
77	  return (
78	    <div className="min-h-screen bg-background flex flex-col">
79	      <TopBar
80	        profile={profile}
81	        onProfileClick={() => setProfileDrawerOpen(true)}
82	        hideRightElements={isCrevidAI}
83	      />
84	
85	      <div className="flex flex-1 overflow-hidden">
86	        <MainSidebar
87	          userType={userType}
88	          profile={profile}
89	          onProfileClick={() => setProfileDrawerOpen(true)}
90	        />
91	
92	        <main className="flex-1 overflow-auto pb-16 md:pb-0 md:ml-[100px]">
93	          {children}
94	        </main>
95	      </div>
96	
97	      <MobileBottomNav />
98	
